import { useEffect, useState, useContext } from 'react';
import { AuthContext } from '../context/AuthContext';
import api from '../services/api';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const { user, logout } = useContext(AuthContext);

  useEffect(() => {
    const fetchTasks = async () => {
      try {
        const res = await api.get('/tasks');
        setTasks(res.data);
      } catch (err) {
        console.error('Tasks nahi mil rahe');
      }
    };
    fetchTasks();
  }, []);

  // Dashboard logic: Overdue tasks calculate karo[cite: 3]
  const overdueCount = tasks.filter(t => new Date(t.deadline) < new Date() && t.status !== 'Done').length;

  return (
    <div style={{ padding: '20px' }}>
      <h1>Dashboard ({user?.role})</h1>
      <button onClick={logout}>Logout</button>
      
      <div style={{ display: 'flex', gap: '20px', margin: '20px 0' }}>
        <div style={{ border: '1px solid black', padding: '10px' }}>Total Tasks: {tasks.length}</div>
        <div style={{ border: '1px solid red', padding: '10px', color: 'red' }}>Overdue: {overdueCount}</div>
      </div>

      {/* Sirf Admin ko dikhega */}
      {user?.role === 'Admin' && (
        <div style={{ background: '#f0f0f0', padding: '10px', marginBottom: '20px' }}>
          <h3>Admin Panel: Naya Task Assign Karo</h3>
          <p>(Yahan hum ek form add karenge)</p>
        </div>
      )}

      <h3>Task List</h3>
      <ul>
        {tasks.map(t => (
          <li key={t._id}>{t.title} - <b>{t.status}</b> (Deadline: {new Date(t.deadline).toLocaleDateString()})</li>
        ))}
      </ul>
    </div>
  );
};

export default Dashboard;
